import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { listenAuction, startAuction, closeAuction, listenPlayers, resetAllWins } from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });

  useEffect(() => {
    const unsubs = [
      listenAuction(setAuction),
      listenPlayers(setPlayers)
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleStart = async () => {
    try {
      await startAuction(settings);
      toast.success("Auction started! Players can now bid.");
    } catch (err) { toast.error(err.message); }
  };

  const handleClose = async () => {
    if (!window.confirm("Close auction and announce winner?")) return;
    try {
      await closeAuction(auction);
      toast.success("Auction closed successfully!");
    } catch (err) { toast.error(err.message); }
  };

  return (
    <div className="page-wide">
      <div className="navbar">
        <div className="navbar-brand">👑 Admin Panel</div>
        <button className="btn btn-ghost btn-sm" onClick={() => window.location.reload()}>Refresh</button>
      </div>

      <div className="card">
        <h3 className="card-title">Group Settings</h3>
        <div style={{ display: 'flex', gap: '15px', marginTop: '15px' }}>
          <div className="form-group">
            <label className="form-label">Monthly Amount (₹)</label>
            <input type="number" className="form-input" value={settings.monthlyAmount} 
              onChange={e => setSettings({...settings, monthlyAmount: Number(e.target.value)})} />
          </div>
          <div className="form-group">
            <label className="form-label">Total Players</label>
            <input type="number" className="form-input" value={settings.totalPlayers} 
              onChange={e => setSettings({...settings, totalPlayers: Number(e.target.value)})} />
          </div>
        </div>
      </div>

      <div className="navbar">
  <div className="navbar-brand">👑 Admin Panel</div>
  <div style={{ display: 'flex', gap: '10px' }}>
     <button className="btn btn-ghost btn-sm" onClick={() => window.location.reload()}>Refresh</button>
     <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
          </div>
      </div>

      <div className="card" style={{ textAlign: 'center' }}>
        {auction?.active ? (
          <>
            <div className="badge badge-green">AUCTION LIVE</div>
            <h2 style={{ margin: '15px 0' }}>Current Bid: ₹{auction.currentBid}</h2>
            <button className="btn btn-danger btn-full" onClick={handleClose}>End Auction & Save Winner</button>
          </>
        ) : (
          <button className="btn btn-primary btn-full" onClick={handleStart}>Start New Monthly Auction</button>
        )}
      </div>
    </div>


  );
}
